import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

// GET /api/pages/homepage - Get homepage data
export async function GET(request: NextRequest) {
  try {
    const page = await prisma.page.findFirst({
      where: { 
        isHomepage: true,
        status: 'published',
      },
    });

    if (!page) {
      return NextResponse.json({ page: null });
    }

    // Parse builderData JSON
    let sections = [];
    if (page.builderData) {
      const parsed = JSON.parse(page.builderData);
      sections = parsed.sections || parsed || [];
    }

    const pageData = {
      ...page,
      builderData: sections,
    };

    return NextResponse.json({ page: pageData });
  } catch (error) {
    console.error('Homepage GET error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}
